#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    set<int> a;
    cin >> n;
    for (int i = 0; i < n; i++) {
        int t;
        cin >> t;
        a.insert(t);
    }
    cout << a.size() << endl;
    for (auto i : a) {
        cout << i << ' ';
    }
    return 0;
}
